import java.lang.Long

fun solve(n: Long, k: Long): Long {
    if (k == 0L) {
        return if (n >= 1) 1 else 0
    }
    val maxM = 60
    val depthArray = IntArray(maxM + 1)
    depthArray[1] = 0
    for (i in 2..maxM) {
        val pop = Integer.bitCount(i)
        depthArray[i] = 1 + depthArray[pop]
    }
    val setS = (1..maxM).filter { depthArray[it] == (k - 1).toInt() }

    var total = 0L
    for (m in setS) {
        var cnt = countNumbersWithPopcount(n, m)
        if (m == 1) {
            cnt -= 1
        }
        total += cnt
    }
    return total
}

fun countNumbersWithPopcount(n: Long, m: Int): Long {
    if (m == 0) return 0
    val s = java.lang.Long.toBinaryString(n)
    val L = s.length
    val dp = Array(L + 1) { Array(2) { LongArray(L + 1) } }
    for (i in 0..L) {
        for (tight in 0..1) {
            for (count in 0..L) {
                dp[i][tight][count] = 0
            }
        }
    }
    dp[0][1][0] = 1
    for (i in 0 until L) {
        for (tight in 0..1) {
            for (count in 0..L) {
                if (dp[i][tight][count] == 0L) continue
                val bound = if (tight == 1) s[i] - '0' else 1
                for (d in 0..bound) {
                    val newTight = if (tight == 1 && d == bound) 1 else 0
                    val newCount = count + (if (d == 1) 1 else 0)
                    if (newCount <= L) {
                        dp[i + 1][newTight][newCount] += dp[i][tight][count]
                    }
                }
            }
        }
    }
    return dp[L][0][m] + dp[L][1][m]
}
```

### Explanation
1. **Precompute Depths**:
   - We first compute the depth for all numbers from 1 to 60. The depth of 1 is 0, and for any number i > 1, the depth is 1 plus the depth of its popcount.

2. **Collect Valid Popcounts**:
   - For a given k, we collect all numbers m (1 ≤ m ≤ 60) such that depth[m] = k-1. These m values are the valid popcounts for numbers x that will have depth k.

3. **Count Numbers with Valid Popcounts**:
   - Using digit DP, we count numbers in [1, n] with popcount exactly m for each m in the collected set. The digit DP processes each bit of n's binary representation, tracking tight constraints and the count of set bits.
   - Special handling for m=1: we subtract 1 to exclude the number 1, which has depth 0 (not k, since k ≥ 1).

4. **Sum Results**:
   - The total count is the sum of counts for all valid m values, adjusted for m=1.

This approach efficiently handles the large constraint (n up to 10^15) by leveraging dynamic programming and precomputing necessary depths for small numbers.

